/* Tymczasowy synchroniczny loader pdf-lib dla Kalkulator/test.html.
 * Docelowo ten plik powinien zostać podmieniony na pełny lokalny build:
 * pdf-lib/dist/pdf-lib.min.js
 */
(function loadPdfLibSynchronously(){
  if (window.PDFLib) return;
  document.write('<script src="https://cdn.jsdelivr.net/npm/pdf-lib@1.17.1/dist/pdf-lib.min.js"><\/script>');
})();
